const rows = {{node:search_existing_pi_link.data.data}};
const arr = Array.isArray(rows) ? rows : (rows ? [rows] : []);
return { alreadyLinked: arr.length > 0 ? 1 : 0 };

const rows = {{node:search_si.data.data}};
const si = Array.isArray(rows) ? rows[0] : rows;
const tableSi = (si && si.table_si) ? si.table_si : [];
const soSet = {}; const gdSet = {};
for (const r of tableSi) {
  if (!r) continue;
  if ((r.invoice_qty || 0) <= 0) continue;
  if (r.line_so_id) soSet[String(r.line_so_id)] = true;
  if (r.line_gd_id) gdSet[String(r.line_gd_id)] = true;
}
let soIds = Object.keys(soSet); if (soIds.length === 0) soIds = ["0"];
let gdIds = Object.keys(gdSet); if (gdIds.length === 0) gdIds = ["0"];
return { soIds: soIds, gdIds: gdIds, siNo: (si && si.sales_invoice_no) ? si.sales_invoice_no : '' };

const sopoRows = {{node:search_sopo_link.data.data}};
const gdgrRows = {{node:search_gdgr_link.data.data}};
const sopo = Array.isArray(sopoRows) ? sopoRows : (sopoRows ? [sopoRows] : []);
const gdgr = Array.isArray(gdgrRows) ? gdgrRows : (gdgrRows ? [gdgrRows] : []);
const soPoMap = {}; const gdGrMap = {};
const poSet = {}; const grSet = {};
for (const r of sopo) {
  if (!r || !r.target_doc_id || !r.source_doc_id) continue;
  soPoMap[String(r.target_doc_id)] = { poId: String(r.source_doc_id), poNo: r.source_doc_no || '' };
  poSet[String(r.source_doc_id)] = true;
}
for (const r of gdgr) {
  if (!r || !r.source_doc_id || !r.target_doc_id) continue;
  gdGrMap[String(r.source_doc_id)] = { grId: String(r.target_doc_id), grNo: r.target_doc_no || '' };
  grSet[String(r.target_doc_id)] = true;
}
let poIds = Object.keys(poSet); if (poIds.length === 0) poIds = ["0"];
let grIds = Object.keys(grSet); if (grIds.length === 0) grIds = ["0"];
return { soPoMap: soPoMap, gdGrMap: gdGrMap, poIds: poIds, grIds: grIds };

const siRows = {{node:search_si.data.data}};
const si = Array.isArray(siRows) ? siRows[0] : siRows;
const tableSi = (si && si.table_si) ? si.table_si : [];
const poRows = {{node:search_po.data.data}};
const pos = Array.isArray(poRows) ? poRows : (poRows ? [poRows] : []);
const grRows = {{node:search_gr.data.data}};
const grs = Array.isArray(grRows) ? grRows : (grRows ? [grRows] : []);
const soPoMap = {{node:code_doc_maps.data.soPoMap}} || {};
const gdGrMap = {{node:code_doc_maps.data.gdGrMap}} || {};
const itsRows = {{node:search_its.data.data}};
const itsArr = Array.isArray(itsRows) ? itsRows : (itsRows ? [itsRows] : []);
const aliasRows = {{node:search_alias.data.data}};
const aliasArr = Array.isArray(aliasRows) ? aliasRows : (aliasRows ? [aliasRows] : []);
const buyerOrg = {{workflowparams:buyer_org}} || '';

const roundPrice = (v) => parseFloat(parseFloat(v || 0).toFixed(4));
const round3 = (v) => Math.round((parseFloat(v) || 0) * 1000) / 1000;

// Item Alias: buyer item/uom -> seller item (+ conversion_rate). Cross-org, the SI
// carries the SELLER item id while PO/GR lines carry the BUYER item id; bridge here.
const aliasByItemUom = {}; const aliasByItem = {};
for (const a of aliasArr) {
  if (!a || !a.seller_item_id) continue;
  aliasByItemUom[String(a.buyer_item_id) + '|' + String(a.buyer_uom_id)] = a;
  if (aliasByItem[String(a.buyer_item_id)] === undefined) aliasByItem[String(a.buyer_item_id)] = a;
}
const aliasFor = (buyerItem, buyerUom) => {
  const k = String(buyerItem) + '|' + String(buyerUom);
  if (aliasByItemUom[k]) return aliasByItemUom[k];
  if (aliasByItem[String(buyerItem)]) return aliasByItem[String(buyerItem)];
  return null;
};
const toSeller = (buyerItem, buyerUom) => {
  const a = aliasFor(buyerItem, buyerUom);
  return a ? String(a.seller_item_id) : String(buyerItem); // fallback: same id (non cross-org)
};

// index lookups
const poById = {}; for (const po of pos) { if (po && po.id) poById[String(po.id)] = po; }
const grById = {}; for (const gr of grs) { if (gr && gr.id) grById[String(gr.id)] = gr; }
const poLineById = {};
for (const po of pos) {
  const lines = (po && po.table_po) ? po.table_po : [];
  for (const ln of lines) { if (ln && ln.id) poLineById[String(po.id) + '|' + String(ln.id)] = { po: po, ln: ln }; }
}

// position counters for seller-item match (handles repeated items). NO fallback
// match — an exhausted slot returns null so the extra SI line is dropped (it has
// no corresponding buyer line), instead of double-binding to the same PO/GR line.
const poUsed = {}; const grUsed = {};
// SO-source: match within the resolved PO by seller item + position.
const pickPoLine = (lines, key, sellerItemId, usedMap) => {
  let n = 0;
  const slot = key + '|' + String(sellerItemId);
  for (const ln of lines) {
    if (!ln || ln.parent_or_child === 'Child') continue;
    if (String(toSeller(ln.item_id, ln.quantity_uom)) !== String(sellerItemId)) continue;
    if (n === (usedMap[slot] || 0)) { usedMap[slot] = (usedMap[slot] || 0) + 1; return ln; }
    n++;
  }
  return null;
};
// GD-source: match a GR line by seller item AND the line's own PO (from the SI
// line's SO -> soPoMap). This binds each line to the GR line of ITS purchase
// order, so same-item lines across different SOs/POs never cross-match.
const pickGrLine = (lines, key, sellerItemId, expectedPoId, usedMap) => {
  let n = 0;
  const slot = key + '|' + String(expectedPoId) + '|' + String(sellerItemId);
  for (const ln of lines) {
    if (!ln || ln.parent_or_child === 'Child') continue;
    if (String(ln.line_po_id) !== String(expectedPoId)) continue;
    if (String(toSeller(ln.item_id, ln.item_uom)) !== String(sellerItemId)) continue;
    if (n === (usedMap[slot] || 0)) { usedMap[slot] = (usedMap[slot] || 0) + 1; return ln; }
    n++;
  }
  return null;
};

const tablePi = [];
let totalGross = 0, totalDiscount = 0, totalTax = 0, totalAmount = 0;
const poIdSet = {}; const grIdSet = {};
const poNoSet = {}; const grNoSet = {};
let supplierId = ''; let currencyCode = ''; let paymentTermId = ''; let anyGr = false;

for (const sline of tableSi) {
  if (!sline) continue;
  const sellerQty = Number(sline.invoice_qty) || 0;   // qty in SELLER uom
  if (sellerQty <= 0) continue;
  const sellerItemId = sline.material_id;             // SELLER item id

  let poLine = null, po = null, grLine = null, gr = null;
  let lineGrId = '', grLineId = '', grNo = '';

  // Each SI line carries its SO; resolve that SO's PO. A line whose SO is NOT
  // internally linked (no PO) is dropped (per the partial/per-line rule).
  const soMap = soPoMap[String(sline.line_so_id)];
  const expectedPoId = soMap ? String(soMap.poId) : '';
  if (!expectedPoId) continue;

  if (sline.line_gd_id && String(sline.line_gd_id) !== '') {
    // GD-sourced -> GR (buyer org), bound to this line's own PO
    const m = gdGrMap[String(sline.line_gd_id)];
    if (!m) continue; // GD has no linked GR -> drop this line
    gr = grById[String(m.grId)];
    if (!gr) continue;
    grLine = pickGrLine((gr.table_gr || []), String(gr.id), sellerItemId, expectedPoId, grUsed);
    if (!grLine) continue; // no GR line for this item+PO -> drop
    lineGrId = gr.id; grLineId = grLine.id; grNo = gr.goods_receiving_number || m.grNo || '';
    anyGr = true;
    const pk = String(grLine.line_po_id) + '|' + String(grLine.po_line_item_id);
    const found = poLineById[pk];
    if (found) { po = found.po; poLine = found.ln; }
    else { po = poById[String(grLine.line_po_id)] || null; }
  } else {
    // SO-sourced -> PO (buyer org)
    po = poById[expectedPoId];
    if (!po) continue;
    poLine = pickPoLine((po.table_po || []), String(po.id), sellerItemId, poUsed);
    if (!poLine) continue;
  }
  if (!po) continue;

  if (!supplierId && po.po_supplier_id) supplierId = po.po_supplier_id;
  if (!currencyCode && po.po_currency) currencyCode = po.po_currency;
  if (!paymentTermId && po.po_payment_term) paymentTermId = po.po_payment_term;

  // BUYER item/uom for the PI line, taken from the buyer PO/GR line
  const buyerLine = poLine || grLine || {};
  const buyerItemId = grLine ? grLine.item_id : (poLine ? poLine.item_id : sellerItemId);
  const buyerUom = grLine ? grLine.item_uom : (poLine ? poLine.quantity_uom : null);
  // Convert SELLER qty -> BUYER qty via alias conversion_rate (seller = buyer * rate)
  const aEntry = aliasFor(buyerItemId, buyerUom);
  const rate = aEntry ? (parseFloat(aEntry.conversion_rate) || 1) : 1;
  const invQty = rate ? round3(sellerQty / rate) : sellerQty;

  // price/tax/discount from the buyer PO line (decision 4); price from GR line if GR-sourced
  const taxSrc = poLine || grLine || {};
  const unitPrice = grLine ? (grLine.unit_price) : (poLine ? poLine.unit_price : 0);
  const orderDiscount = taxSrc.discount || 0;
  let discountUom = taxSrc.discount_uom || '';
  const taxPercent = Number(taxSrc.tax_percent) || 0;
  const taxPreference = taxSrc.tax_preference || '';
  const taxInclusive = taxSrc.tax_inclusive;

  // amounts (replicate the PI form PIcalculation func) on BUYER qty
  const gross = roundPrice(invQty * (Number(unitPrice) || 0));
  let discount = parseFloat(orderDiscount) || 0;
  let discountAmount = 0;
  if (discount > 0 && !discountUom) discountUom = 'Amount';
  if (discountUom && discount !== 0) {
    if (discountUom === 'Amount') discountAmount = roundPrice(discount);
    else if (discountUom === '%') discountAmount = roundPrice((gross * discount) / 100);
    if (discountAmount > gross) { discount = 0; discountAmount = 0; }
  }
  const afterDisc = roundPrice(gross - discountAmount);
  let taxAmount = 0; let finalAmount = afterDisc;
  if (taxPercent) {
    const d = taxPercent / 100;
    if (taxInclusive === 1) { taxAmount = roundPrice(afterDisc - afterDisc / (1 + d)); finalAmount = afterDisc; }
    else { taxAmount = roundPrice(afterDisc * d); finalAmount = roundPrice(afterDisc + taxAmount); }
  }

  totalGross = roundPrice(totalGross + gross);
  totalDiscount = roundPrice(totalDiscount + discountAmount);
  totalTax = roundPrice(totalTax + taxAmount);
  totalAmount = roundPrice(totalAmount + finalAmount);

  const linePoId = grLine ? grLine.line_po_id : po.id;
  const poLineId = grLine ? grLine.po_line_item_id : (poLine ? poLine.id : '');
  const poNo = grLine ? (grLine.line_po_no || po.purchase_order_no) : po.purchase_order_no;
  const recvQty = grLine ? grLine.received_qty : (poLine ? poLine.received_qty : 0);
  const orderedQty = grLine ? grLine.ordered_qty : (poLine ? poLine.quantity : 0);
  const availInv = grLine
    ? round3((Number(grLine.received_qty) || 0) - (Number(grLine.invoice_qty) || 0))
    : (poLine ? round3((Number(poLine.quantity) || 0) - (Number(poLine.invoice_qty) || 0)) : 0);

  if (linePoId) poIdSet[String(linePoId)] = true;
  if (poNo) poNoSet[String(poNo)] = true;
  if (lineGrId) { grIdSet[String(lineGrId)] = true; if (grNo) grNoSet[String(grNo)] = true; }

  tablePi.push({
    material_id: buyerItemId || '',
    material_name: (taxSrc.item_name) || sline.material_name || '',
    item_desc: taxSrc.item_desc || sline.item_desc || '',
    more_desc: taxSrc.more_desc || sline.more_desc || '',
    purchase_order_no: poNo || '',
    goods_receiving_no: grNo || '',
    order_qty: orderedQty,
    received_qty: recvQty,
    invoice_qty: invQty,
    quantity_uom: buyerUom,
    order_unit_price: unitPrice,
    order_gross: gross,
    order_discount: discount,
    discount_uom: discountUom,
    discount_amount: discountAmount,
    tax_preference: taxPreference,
    tax_percent: taxPercent,
    tax_rate_percent: taxPercent,
    tax_amount: taxAmount,
    tax_inclusive: taxInclusive,
    invoice_amount: finalAmount,
    pi_amount: finalAmount,
    available_inv_qty: availInv,
    po_line_id: poLineId,
    gr_line_id: grLineId,
    line_po_id: linePoId,
    line_gr_id: lineGrId,
    item_category_id: taxSrc.item_category_id || null,
    tariff_id: taxSrc.tariff_id || null,
    line_remark_1: taxSrc.line_remark_1 || '',
    line_remark_2: taxSrc.line_remark_2 || '',
  });
}

// ITS row pick for buyer plant (supplier-matched, else enabled, else first)
let itsMatch = itsArr.find(function (r) { return r && String(r.buyer_supplier_id) === String(supplierId); });
if (!itsMatch) itsMatch = itsArr.find(function (r) { return r && Number(r.auto_create_pi) === 1; }) || itsArr[0] || null;
const buyerPlant = (itsMatch && itsMatch.buyer_plant_id) ? itsMatch.buyer_plant_id : '';

let poIds = Object.keys(poIdSet); if (poIds.length === 0) poIds = [];
let grIds = Object.keys(grIdSet); if (grIds.length === 0) grIds = [];
const supplierIds = supplierId ? [String(supplierId)] : ["0"];

return {
  tablePi: tablePi,
  invoiceSubtotal: totalGross,
  invoiceTotalDiscount: totalDiscount,
  invoiceTaxesAmount: totalTax,
  invoiceTotal: totalAmount,
  supplierId: supplierId || '',
  supplierIds: supplierIds,
  currencyCode: currencyCode || '',
  paymentTermId: paymentTermId || '',
  buyerPlant: buyerPlant,
  organizationId: buyerOrg,
  poIds: poIds,
  grIds: grIds,
  poNos: Object.keys(poNoSet).join(', '),
  grNos: Object.keys(grNoSet).join(', '),
  referenceType: anyGr ? 'Document - GR' : 'Document - PO',
  lineCount: tablePi.length,
  siNo: (si && si.sales_invoice_no) ? si.sales_invoice_no : ''
};

const rows = {{node:search_supplier.data.data}};
const s = Array.isArray(rows) ? rows[0] : rows;
const countryIds = [];
const stateIds = [];
let currencyId = '';
if (s) {
  currencyId = s.currency_id || '';
  const addrs = (s.address_list || []).filter(a => a.switch_save_as_default);
  for (const a of addrs) {
    if (a.address_country_id) countryIds.push(String(a.address_country_id));
    if (a.adddress_state) stateIds.push(String(a.adddress_state));
  }
}
let cIds = Array.from(new Set(countryIds)); if (cIds.length === 0) cIds = ["0"];
let sIds = Array.from(new Set(stateIds)); if (sIds.length === 0) sIds = ["0"];
return { countryIds: cIds, stateIds: sIds, currencyIds: currencyId ? [String(currencyId)] : ["0"] };

const tablePi = {{node:code_build_lines.data.tablePi}} || [];
const supplierId = {{node:code_build_lines.data.supplierId}} || '';
const poCurrency = {{node:code_build_lines.data.currencyCode}} || '';
const poIds = {{node:code_build_lines.data.poIds}} || [];
const grIds = {{node:code_build_lines.data.grIds}} || [];
const poNos = {{node:code_build_lines.data.poNos}} || '';
const grNos = {{node:code_build_lines.data.grNos}} || '';
const referenceType = {{node:code_build_lines.data.referenceType}} || 'Document - PO';
const orgId = {{node:code_build_lines.data.organizationId}} || '';
const plantId = {{node:code_build_lines.data.buyerPlant}} || '';
const paymentTermId = {{node:code_build_lines.data.paymentTermId}} || '';
const siNo = {{node:code_build_lines.data.siNo}} || '';
const subtotal = {{node:code_build_lines.data.invoiceSubtotal}} || 0;
const totalDiscount = {{node:code_build_lines.data.invoiceTotalDiscount}} || 0;
const totalTax = {{node:code_build_lines.data.invoiceTaxesAmount}} || 0;
const total = {{node:code_build_lines.data.invoiceTotal}} || 0;

const accRows = {{node:search_acc.data.data}};
const accArr = Array.isArray(accRows) ? accRows : (accRows ? [accRows] : []);
const accType = accArr.length > 0 ? accArr[0].acc_integration_type : '';
const ruleRows = {{node:search_pi_rule.data.data}};
const ruleArr = Array.isArray(ruleRows) ? ruleRows : (ruleRows ? [ruleRows] : []);
const piNoType = ruleArr.length > 0 ? ruleArr[0].id : '';

const supplierRows = {{node:search_supplier.data.data}};
const supplier = Array.isArray(supplierRows) ? supplierRows[0] : supplierRows;
const currencyRows = {{node:search_supplier_currency.data.data}};
const currencyArr = Array.isArray(currencyRows) ? currencyRows : (currencyRows ? [currencyRows] : []);
const supplierCurrencyCode = currencyArr.length > 0 ? currencyArr[0].currency_code : '';
const purposeRows = {{node:search_addr_purpose.data.data}};
const purposeArr = Array.isArray(purposeRows) ? purposeRows : (purposeRows ? [purposeRows] : []);
const shippingPurposeId = purposeArr.length > 0 ? purposeArr[0].id : '';
const countryRows = {{node:search_addr_country.data.data}};
const countryArr = Array.isArray(countryRows) ? countryRows : (countryRows ? [countryRows] : []);
const stateRows = {{node:search_addr_state.data.data}};
const stateArr = Array.isArray(stateRows) ? stateRows : (stateRows ? [stateRows] : []);
const countryMap = {}; for (const c of countryArr) { if (c && c.id) countryMap[String(c.id)] = c.country_name; }
const stateMap = {}; for (const s of stateArr) { if (s && s.id) stateMap[String(s.id)] = s.state_name; }

let currencyCode = poCurrency;
if (supplierCurrencyCode) currencyCode = supplierCurrencyCode;

const addrFields = {};
if (supplier) {
  const addresses = (supplier.address_list || []).filter((a) => a.switch_save_as_default);
  for (const address of addresses) {
    const country = address.address_country_id ? (countryMap[String(address.address_country_id)] || '') : '';
    const state = address.adddress_state ? (stateMap[String(address.adddress_state)] || '') : '';
    const isShipping = address.address_purpose_id === shippingPurposeId;
    const addressType = isShipping ? 'shipping' : 'billing';
    const addressTypeUpperCase = isShipping ? 'Shipping' : 'Billing';
    const lineParts = [address.address_line_1, address.address_line_2, address.address_line_3, address.address_line_4].filter((l) => l);
    const addressLines = lineParts.join((lineParts[lineParts.length - 1] || '').endsWith(',') ? ' ' : ', ');
    const cityParts = [address.address_city, address.address_postal_code, address.adddress_state ? state : '', address.address_country_id ? country : ''].filter((d) => d);
    const cityDetails = cityParts.join((cityParts[cityParts.length - 1] || '').endsWith(',') ? ' ' : ', ');
    const addressAttention = address.address_attention ? '\nAttention: ' + address.address_attention : '';
    const addressPurposeName = '\n' + addressTypeUpperCase + ' Address';
    const personParts = [address.address_name, address.address_phone].filter((p) => p);
    const addressPerson = personParts.length > 0 ? personParts.join(' | ') : '';
    const formattedAddress = [addressPerson, addressPurposeName, addressLines, cityDetails, addressAttention].filter(Boolean).join('\n');
    addrFields[addressType + '_address_line_1'] = address.address_line_1;
    addrFields[addressType + '_address_line_2'] = address.address_line_2;
    addrFields[addressType + '_address_line_3'] = address.address_line_3;
    addrFields[addressType + '_address_line_4'] = address.address_line_4;
    addrFields[addressType + '_address_city'] = address.address_city;
    addrFields[addressType + '_address_state'] = address.adddress_state;
    addrFields[addressType + '_postal_code'] = address.address_postal_code;
    addrFields[addressType + '_address_country'] = address.address_country_id;
    addrFields[addressType + '_address_name'] = address.address_name;
    addrFields[addressType + '_address_phone'] = address.address_phone;
    addrFields[addressType + '_attention'] = address.address_attention;
    addrFields['pi_' + addressType + '_address'] = formattedAddress;
  }
}

const today = new Date().toISOString().split('T')[0];

const piAllData = Object.assign({
  pi_status: 'Completed',
  page_status: 'Add',
  plant_id: plantId,
  organization_id: orgId,
  supplier_name: supplierId,
  currency_code: currencyCode,
  acc_integration_type: accType,
  purchase_invoice_no: '',
  purchase_invoice_no_type: piNoType,
  invoice_date: today,
  pi_description: 'Auto-created from Sales Invoice ' + siNo,
  invoice_payment_term_id: paymentTermId,
  reference_type: referenceType,
  po_id: poIds,
  gr_id: grIds,
  po_no_display: poNos,
  gr_no_display: grNos,
  invoice_subtotal: subtotal,
  invoice_total_discount: totalDiscount,
  invoice_taxes_amount: totalTax,
  invoice_total: total,
  total_gross_currency: currencyCode,
  total_discount_currency: currencyCode,
  total_tax_currency: currencyCode,
  total_amount_currency: currencyCode,
  exchange_rate_currency: currencyCode,
  table_pi: tablePi
}, addrFields);

return { piAllData: piAllData, lineCount: tablePi.length };

const r = {{node:wf_complete_pi.data}};
const d = (r && r.data && typeof r.data === 'object') ? r.data : r;
let code = '';
let message = '';
let piId = '';
let piNo = '';
if (d) {
  code = (d.code !== undefined && d.code !== null) ? d.code : '';
  message = (d.message !== undefined && d.message !== null) ? d.message : (d.msg || '');
  piId = d.id || '';
  piNo = d.pi_no || '';
}
const piOk = (piId && String(piId) !== '') ? 1 : 0;
return { piOk: piOk, piCode: String(code || ''), piMessage: message || '', piId: piId || '', piNo: piNo || '' };
